class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        int n = answerKey.size();
        int maxT = 0, maxF = 0, left = 0, countT = 0, countF = 0;
        for (int right = 0; right < n; right++) {
            countT += (answerKey[right] == 'T');
            countF += (answerKey[right] == 'F');
            while (countT > k && left <= right) {
                countT -= (answerKey[left] == 'T');
                countF -= (answerKey[left] == 'F');
                left++;
            }
            maxT = max(maxT, right - left + 1);
            countT -= (answerKey[left] == 'T');
            countF -= (answerKey[left] == 'F');
            left++;
            countT += (answerKey[left - 1] == 'T');
            countF += (answerKey[left - 1] == 'F');
            maxF = max(maxF, right - left + 1);
        }
        return max(maxT, maxF);
    }
};
```

